 1	import * as React from 'react';
 2	
 3	import {
 4	  V1VirtualMachineInstance,
 5	  V1VirtualMachineInstanceGuestOSUser,
 6	} from '@kubevirt-ui/kubevirt-api/kubevirt';
 7	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import { VirtualizedTable } from '@openshift-console/dynamic-plugin-sdk';
10	import { Bullseye, Icon, Title } from '@patternfly/react-core';
11	import { LinkIcon } from '@patternfly/react-icons';
12	
13	import useGuestOS from '../../../../hooks/useGuestOS';
14	
15	import useActiveUsersColumns from './hooks/useActiveUsersColumns';
16	import ActiveUserListRow from './ActiveUserListRow';
17	
18	type ActiveUserListProps = {
19	  pathname: string;
20	  vmi: V1VirtualMachineInstance;
21	};
22	
23	const ActiveUserList: React.FC<ActiveUserListProps> = ({ pathname, vmi }) => {
24	  const { t } = useKubevirtTranslation();
25	  const columns = useActiveUsersColumns();
26	  const [{ userList = [] }, loaded, , isGuestAgentConnected] = useGuestOS(vmi);
27	
28	  return (
29	    <div>
30	      <a className="link-icon" href={`${pathname}#logged-in-users`}>
31	        <Icon size="sm">
32	          <LinkIcon />
33	        </Icon>
34	      </a>
35	      <Title className="co-section-heading" headingLevel="h2">
36	        {t('Active users')}
37	      </Title>
38	      {isGuestAgentConnected ? (
39	        <VirtualizedTable<V1VirtualMachineInstanceGuestOSUser>
40	          NoDataEmptyMsg={() => (
41	            <Bullseye>
42	              <MutedTextSpan text={t('No active users')} />
43	            </Bullseye>
44	          )}
45	          columns={columns}
46	          data={userList}
47	          loaded={loaded}
48	          loadError={false}
49	          Row={ActiveUserListRow}
50	          unfilteredData={userList}
51	        />
52	      ) : (
53	        <Bullseye>
54	          <MutedTextSpan text={t('Guest agent is required')} />
55	        </Bullseye>
56	      )}
57	    </div>
58	  );
59	};
60	
61	export default ActiveUserList;

